CREATE TABLE `facturaciones` (
  `id` int(11) NOT NULL,
  `usuario_id` int(11) NOT NULL,
  `nombre_usuario` varchar(255) DEFAULT NULL,
  `no_prescripcion` varchar(20) NOT NULL COMMENT 'Campo 1: Número de Prescripción',
  `tipo_tec` varchar(1) NOT NULL COMMENT 'Campo 2: Tipo Servicio/Tecnología (M/P/D/N/S)',
  `con_tec` varchar(2) NOT NULL COMMENT 'Campo 3: Consecutivo Orden',
  `tipo_id_paciente` varchar(2) NOT NULL COMMENT 'Campo 4: Tipo Documento Paciente',
  `no_id_paciente` varchar(17) NOT NULL COMMENT 'Campo 5: Número ID Paciente',
  `no_entrega` varchar(4) NOT NULL COMMENT 'Campo 6: Número Entrega',
  `no_sub_entrega` varchar(2) NOT NULL COMMENT 'Campo 7: Número Sub Entrega',
  `no_factura` varchar(96) NOT NULL COMMENT 'Campo 8: Número de Factura Electrónica',
  `no_id_eps` varchar(17) NOT NULL COMMENT 'Campo 9: NIT de EPS que realiza recobro',
  `cod_eps` varchar(6) NOT NULL COMMENT 'Campo 10: Código de EPS',
  `cod_ser_tec_entregado` varchar(20) NOT NULL COMMENT 'Campo 11: Código servicio/tecnología entregado',
