  `valor_unit_facturado` decimal(16,2) NOT NULL COMMENT 'Campo 13: Valor Unitario Facturado',
  `valor_tot_facturado` decimal(16,2) NOT NULL COMMENT 'Campo 14: Valor Total Facturado',
  `cuota_moderadora` decimal(16,2) DEFAULT 0.00 COMMENT 'Campo 15: Cuota Moderadora',
  `copago` decimal(16,2) DEFAULT 0.00 COMMENT 'Campo 16: Copago',
  `dir_paciente` varchar(80) DEFAULT NULL COMMENT 'Dirección del Paciente',
  `token_temporal` varchar(255) NOT NULL COMMENT 'Token temporal del usuario',
  `estado` varchar(50) DEFAULT 'pendiente' COMMENT 'pendiente, completada, cancelada, enviada',
  `respuesta_api` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Respuesta de la API MIPRES' CHECK (json_valid(`respuesta_api`)),
  `http_code` int(3) DEFAULT NULL COMMENT 'Código HTTP de respuesta',
  `fecha_registro` timestamp NOT NULL DEFAULT current_timestamp(),
  `fecha_actualizacion` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

